class EventBus:
    def __init__(self):
        self.handlers = {}
    def subscribe(self, name, handler):
        self.handlers.setdefault(name, []).append(handler)
    def publish(self, name, payload):
        for handler in self.handlers.get(name, []):
            handler(payload)

